import { createRemoteJWKSet, jwtVerify, JWTPayload } from "jose";

export interface UserPayload {
  sub: string;
  email?: string;
  roles?: string[];
  [key: string]: unknown;
}

declare global {
  namespace Express {
    interface Request {
      user?: UserPayload;
    }
  }
}

const JWKS_URI = process.env.JWKS_URI;
const JWT_ISSUER = process.env.JWT_ISSUER;
const JWT_AUDIENCE = process.env.JWT_AUDIENCE;

let jwks: ReturnType<typeof createRemoteJWKSet> | null = null;

function getJWKS(): ReturnType<typeof createRemoteJWKSet> {
  if (!JWKS_URI) {
    throw new Error("JWKS_URI environment variable is not set");
  }
  if (!jwks) {
    jwks = createRemoteJWKSet(new URL(JWKS_URI), {
      cooldownDuration: 30_000,
      cacheMaxAge: 600_000,
    });
  }
  return jwks;
}

function extractPayload(token: JWTPayload): UserPayload {
  return {
    sub: token.sub!,
    email: token.email as string | undefined,
    roles: token.roles as string[] | undefined,
    ...token,
  };
}

export async function requireAuth(
  req: Request,
  res: Response,
  next: NextFunction,
): Promise<void> {
  const header = req.headers.authorization;
  if (!header?.startsWith("Bearer ")) {
    res.status(401).json({ error: "Missing or malformed Authorization header" });
    return;
  }

  const token = header.slice(7);

  try {
    const { payload } = await jwtVerify(token, getJWKS(), {
      algorithms: ["RS256"],
      issuer: JWT_ISSUER,
      audience: JWT_AUDIENCE,
    });

    if (!payload.sub) {
      res.status(401).json({ error: "Token missing sub claim" });
      return;
    }

    req.user = extractPayload(payload);
    next();
  } catch (err) {
    const message =
      err instanceof Error ? err.message : "Token verification failed";
    res.status(401).json({ error: message });
